import fast_hadamard_transform
import torch

from lib import utils

torch._dynamo.config.cache_size_limit = 256

_HAD180_CACHE = None
def get_had180():
    """
    180차원 Hadamard 행렬 생성 (Correct Paley Construction Type I)
    N = 180 = 179 + 1 (179 is prime, 179 ≡ 3 mod 4)
    
    구성 방식: H = S + I
    (S는 Skew-Hadamard Matrix)
    """
    global _HAD180_CACHE
    
    if _HAD180_CACHE is not None:
        return _HAD180_CACHE
    
    p = 179
    
    # 1. Legendre Symbol (이차 잉여) 계산
    # legendre[i] = 1 (이차잉여), -1 (비이차잉여), 0 (0인 경우)
    legendre = [0] * p
    for i in range(1, p):
        # 오일러 판정법: a^((p-1)/2) mod p
        val = pow(i, (p - 1) // 2, p)
        if val == p - 1: # mod p 에서 -1
            legendre[i] = -1
        else:
            legendre[i] = val

    # 2. Jacobsthal Matrix Q 생성
    # Q_ij = legendre((i - j) % p)
    # p=179 ≡ 3 (mod 4) 이므로 Q는 Skew-symmetric (Q^T = -Q)
    indices = torch.arange(p).view(-1, 1) - torch.arange(p).view(1, -1)
    indices = indices % p
    
    leg_tensor = torch.tensor(legendre, dtype=torch.float32)
    Q = leg_tensor[indices]

    # 3. Skew-Hadamard Matrix S 구성
    # S = | 0   1^T |
    #     | -1   Q  |
    S = torch.zeros((p + 1, p + 1), dtype=torch.float32)
    
    # 첫 행은 1 (S_00은 0)
    S[0, 1:] = 1.0
    # 첫 열은 -1 (S_00은 0)
    S[1:, 0] = -1.0
    # 나머지 블록은 Q
    S[1:, 1:] = Q

    # 4. 최종 Hadamard Matrix H = S + I
    # (Skew-Hadamard 행렬에 단위행렬을 더하면 Hadamard 행렬이 됨)
    I = torch.eye(p + 1, dtype=torch.float32)
    H = S + I

    return H
def get_hadK(n, transpose=False):
    hadK, K = None, None
    if n % 180 == 0: # gpt oss 20b
        assert (is_pow2(n // 180))
        K = 180
        hadK = get_had180().T if transpose else get_had180()
    elif n % 172 == 0:  # llama-2-7b up
        assert (is_pow2(n // 172))
        K = 172
        hadK = get_had172().T if transpose else get_had172()
    elif n % 156 == 0:  # llama-1-30b 3x hidden
        assert (is_pow2(n // 156))
        K = 156
        hadK = get_had156().T if transpose else get_had156()
    elif n % 140 == 0:  # llama-1-30b intermediate
        assert (is_pow2(n // 140))
        K = 140
        hadK = get_had140().T if transpose else get_had140()
    elif n % 136 == 0:  # (paroquant-baselines fork)
        assert (is_pow2(n // 136))
        K = 136
        hadK = get_had136().T if transpose else get_had136()
    elif n % 124 == 0:  # falcon 180b
        assert (is_pow2(n // 124))
        K = 124
        hadK = get_had124().T if transpose else get_had124()
    elif n % 116 == 0:  # falcon 180b
        assert (is_pow2(n // 116))
        K = 116
        hadK = get_had116().T if transpose else get_had116()
    elif n % 108 == 0:  # llama-1-13b intermediate
        assert (is_pow2(n // 108))
        K = 108
        hadK = get_had108().T if transpose else get_had108()
    elif n % 100 == 0:  # Qwen3-32B intermediate (paroquant-baselines fork)
        assert (is_pow2(n // 100))
        K = 100
        hadK = get_had100().T if transpose else get_had100()
    elif n % 76 == 0:  # Qwen3-4B intermediate=9728=76*128 (paroquant-baselines fork)
        assert (is_pow2(n // 76))
        K = 76
        hadK = get_had76().T if transpose else get_had76()
    elif n % 60 == 0:  # llama-1-13b 3x hidden
        assert (is_pow2(n // 60))
        K = 60
        hadK = get_had60().T if transpose else get_had60()
    elif n % 52 == 0:  # llama-1-13b 1x hidden
        assert (is_pow2(n // 52))
        K = 52
        hadK = get_had52().T if transpose else get_had52()
    elif n % 36 == 0:
        assert (is_pow2(n // 36))
        K = 36
        hadK = get_had36().T if transpose else get_had36()
    elif n % 28 == 0:
        assert (is_pow2(n // 28))
        K = 28
        hadK = get_had28().T if transpose else get_had28()
    elif n % 20 == 0:
        assert (is_pow2(n // 20))
        K = 20
        hadK = get_had20().T if transpose else get_had20()
    elif n % 12 == 0:
        assert (is_pow2(n // 12))
        K = 12
        hadK = get_had12().T if transpose else get_had12()
    else:
        assert (is_pow2(n))
        K = 1

    return hadK, K


def matmul_hadU(X, transpose=False):
    n = X.shape[-1]
    hadK, K = get_hadK(n, transpose)
    input = X.clone().view(-1, n, 1)
    output = input.clone()
    while input.shape[1] > K:
        input = input.view(input.shape[0], input.shape[1] // 2, 2,
                           input.shape[2])
        output = output.view(input.shape)
        output[:, :, 0, :] = input[:, :, 0, :] + input[:, :, 1, :]
        output[:, :, 1, :] = input[:, :, 0, :] - input[:, :, 1, :]
        output = output.view(input.shape[0], input.shape[1], -1)
        (input, output) = (output, input)
    del output
    utils.clean()
    if K > 1:
        input = torch.bmm(
            hadK.repeat(len(input), 1, 1).to(input.device).to(input.dtype),
            input)
    return input.view(X.shape) / torch.tensor(n).sqrt()


def matmul_hadUt(X):
    return matmul_hadU(X, transpose=True)


torch.library.define("hadamard::hadamard", "(Tensor x, float scale) -> Tensor")


@torch.library.register_fake("hadamard::hadamard")
def hadamard_abstract(x: torch.Tensor, scale: float) -> torch.Tensor:
    return x


@torch.library.impl("hadamard::hadamard", "default")
def hadamard(x: torch.Tensor, scale: float) -> torch.Tensor:
    return fast_hadamard_transform.hadamard_transform(x, scale)


def matmul_hadU_cuda(X, hadK, K, transpose=False):
    n = X.shape[-1]
    if K == 1:
        return torch.ops.hadamard.hadamard(X.contiguous(), n**(-0.5))

    if transpose:
        hadK = hadK.T.contiguous()
    input = X.float().view(-1, K, n // K)
    input = torch.ops.hadamard.hadamard(input.contiguous(), n**(-0.5))
    input = hadK.to(input.device).to(input.dtype) @ input
    return input.to(X.device).to(X.dtype).reshape(X.shape)


def matmul_hadUt_cuda(X, hadK, K):
    return matmul_hadU_cuda(X, hadK, K, transpose=True)


def is_pow2(n):
    return (n & (n - 1) == 0) and (n > 0)


def transform_symbol_to_list(symbol: str, K: int):
    """Parse the '+/-' abbr table format used by paroquant-baselines Hadamard
    blocks (get_had76 / get_had100 / get_had136) into a 2D list of ±1."""
    seq = [1 if c == '+' else -1 for c in symbol if c in '+-']
    if len(seq) % K != 0:
        raise ValueError(f"Length {len(seq)} not divisible by K={K}. Check line breaks.")
    return [seq[i:i+K] for i in range(0, len(seq), K)]


